"""
Dependency Management Guide and Helper Script

This module provides documentation and a small utility script for managing Python
dependency lock files and pinned dependency specifications.

Supported workflows:
- requirements.txt with fully pinned versions and hashes
- Poetry-based pyproject.toml + poetry.lock
- pip-tools workflow using requirements.in -> requirements.txt

Goals:
- Keep development and production environments consistent
- Make dependency updates explicit and repeatable
- Reduce accidental breakage from unpinned or drifting dependencies

Recommended approach:
1. Choose one primary dependency management workflow for the project.
2. Commit the generated lock/specification files to version control.
3. Install dependencies only from the committed lock/spec files in CI/CD.
4. Update dependencies intentionally and review diffs before merging.

------------------------------------------------------------------------------
Workflow A: requirements.txt with hashes
------------------------------------------------------------------------------

Best for teams using pip directly and wanting reproducible installs.

Files:
- requirements.in      : human-edited top-level dependencies
- requirements.txt     : generated pinned dependencies with hashes

Typical setup:
1. Create requirements.in with direct dependencies only, for example:
   Django==5.0.*
   requests>=2.31,<3

2. Compile it into a fully pinned requirements.txt:
   pip install pip-tools
   pip-compile --generate-hashes --resolver=backtracking requirements.in

3. Install in development and production:
   pip install --require-hashes -r requirements.txt

Update flow:
- Edit requirements.in
- Re-run pip-compile
- Review the resulting requirements.txt diff
- Commit the updated lock file

Notes:
- Use --generate-hashes for stronger supply-chain integrity.
- Use --require-hashes during installation so pip rejects unpinned packages.
- For reproducibility, avoid installing directly from unpinned requirements.txt.

------------------------------------------------------------------------------
Workflow B: Poetry
------------------------------------------------------------------------------

Best for projects that want integrated dependency resolution, packaging, and lock management.

Files:
- pyproject.toml  : dependency declarations
- poetry.lock     : locked resolved dependency graph

Typical setup:
1. Add dependencies:
   poetry add Django requests

2. Lock and install:
   poetry lock
   poetry install

3. In CI/CD and production:
   poetry install --no-interaction --no-ansi --only main

Update flow:
- Change dependency constraints in pyproject.toml or run poetry add package@version
- Re-run poetry lock
- Review poetry.lock changes
- Commit both pyproject.toml and poetry.lock

Notes:
- poetry.lock should be committed.
- Use the same Poetry version across the team if possible.
- Production installs should use the lock file, not a fresh resolution.

------------------------------------------------------------------------------
Workflow C: Plain pinned requirements.txt
------------------------------------------------------------------------------

Simplest, but less strict than hashed locks.

Example:
- Django==5.0.6
- requests==2.32.3

Install:
- pip install -r requirements.txt

Best practices:
- Pin exact versions for all direct dependencies.
- Regenerate and review pins regularly.
- Prefer hashes if you need stronger reproducibility.

------------------------------------------------------------------------------
Update Policy
------------------------------------------------------------------------------

Recommended process for dependency changes:
1. Make changes in a dedicated branch.
2. Update the dependency spec/lock file.
3. Run tests and linting.
4. Inspect the diff to understand what changed and why.
5. Merge only after CI passes.

Suggested update cadence:
- Security patches: as soon as practical
- Routine dependency refresh: weekly or biweekly
- Major upgrades: separate, planned work

------------------------------------------------------------------------------
Helper script
------------------------------------------------------------------------------

This script does not replace pip-tools or Poetry. It provides a lightweight
command-line helper that:
- Verifies the expected lock/spec file exists
- Prints suggested generation commands
- Optionally checks that all requirements lines are pinned or hashed
- Can be used in CI as a basic policy check

Usage examples:
- python dependency_lock_helper.py check --requirements requirements.txt
- python dependency_lock_helper.py guide --tool pip-tools
- python dependency_lock_helper.py guide --tool poetry

"""

from __future__ import annotations

import argparse
import os
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, List, Tuple


PINNED_REQ_RE = re.compile(
    r"""
    ^
    \s*
    (?P<name>[A-Za-z0-9_.\-]+)
    \s*
    (?P<specifier>==[^;#\s]+)
    (?P<extras>(?:\[[^\]]+\])?)
    (?P<marker>\s*;.*)?
    (?P<comment>\s*#.*)?
    \s*$
    """,
    re.VERBOSE,
)

HASH_RE = re.compile(r"--hash=sha256:[a-fA-F0-9]{64}")
VERSION_SPEC_RE = re.compile(r"==[^;#\s]+")


@dataclass
class CheckResult:
    ok: bool
    messages: List[str]


def read_lines(path: Path) -> List[str]:
    return path.read_text(encoding="utf-8").splitlines()


def is_comment_or_empty(line: str) -> bool:
    stripped = line.strip()
    return not stripped or stripped.startswith("#")


def line_has_hash(line: str) -> bool:
    return bool(HASH_RE.search(line))


def line_is_pinned(line: str) -> bool:
    if is_comment_or_empty(line):
        return True
    if line.startswith(("-r ", "--requirement ", "-c ", "--constraint ")):
        return True
    if line.startswith(("--index-url", "--extra-index-url", "--trusted-host", "--find-links")):
        return True
    return bool(PINNED_REQ_RE.match(line))


def analyze_requirements(path: Path, require_hashes: bool = False) -> CheckResult:
    messages: List[str] = []
    if not path.exists():
        return CheckResult(False, [f"Missing file: {path}"])

    try:
        lines = read_lines(path)
    except OSError as exc:
        return CheckResult(False, [f"Unable to read {path}: {exc}"])

    ok = True
    for idx, line in enumerate(lines, start=1):
        if is_comment_or_empty(line):
            continue
        if line.startswith(("-", "--")):
            continue

        if not line_is_pinned(line):
            ok = False
            messages.append(f"{path}:{idx}: not pinned exactly: {line.strip()}")
            continue

        if require_hashes and not line_has_hash(line):
            ok = False
            messages.append(f"{path}:{idx}: missing hash: {line.strip()}")

    if ok:
        messages.append(f"{path}: OK")
    return CheckResult(ok, messages)


def find_project_files(project_root: Path) -> List[Path]:
    candidates = [
        project_root / "requirements.txt",
        project_root / "requirements.in",
        project_root / "pyproject.toml",
        project_root / "poetry.lock",
        project_root / "Pipfile",
        project_root / "Pipfile.lock",
    ]
    return [p for p in candidates if p.exists()]


def generate_guide(tool: str) -> str:
    tool = tool.lower().strip()
    if tool == "pip-tools":
        return (
            "pip-tools workflow:\n"
            "1. Edit requirements.in\n"
            "2. Run: pip install pip-tools\n"
            "3. Run: pip-compile --generate-hashes --resolver=backtracking requirements.in\n"
            "4. Install with: pip install --require-hashes -r requirements.txt\n"
            "5. Commit requirements.in and requirements.txt\n"
        )
    if tool == "poetry":
        return (
            "Poetry workflow:\n"
            "1. Edit pyproject.toml or run: poetry add <package>\n"
            "2. Run: poetry lock\n"
            "3. Install with: poetry install --no-interaction --no-ansi\n"
            "4. Production install with: poetry install --no-interaction --no-ansi --only main\n"
            "5. Commit pyproject.toml and poetry.lock\n"
        )
    if tool == "plain":
        return (
            "Plain requirements.txt workflow:\n"
            "1. Pin every direct dependency exactly, e.g. package==1.2.3\n"
            "2. Prefer generating the file from a lock workflow or pip freeze in a controlled environment\n"
            "3. Install with: pip install -r requirements.txt\n"
            "4. Commit requirements.txt\n"
        )
    return f"Unknown tool: {tool}"


def cmd_check(args: argparse.Namespace) -> int:
    project_root = Path(args.project_root).resolve()
    files = find_project_files(project_root)

    if args.requirements:
        result = analyze_requirements(Path(args.requirements), require_hashes=args.require_hashes)
        for msg in result.messages:
            print(msg)
        return 0 if result.ok else 1

    if not files:
        print(f"No known dependency files found in {project_root}")
        return 1

    overall_ok = True
    for path in files:
        if path.name == "requirements.txt":
            result = analyze_requirements(path, require_hashes=args.require_hashes)
            for msg in result.messages:
                print(msg)
            overall_ok = overall_ok and result.ok
        else:
            print(f"{path}: present")

    return 0 if overall_ok else 1


def cmd_guide(args: argparse.Namespace) -> int:
    print(generate_guide(args.tool))
    return 0


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="dependency_lock_helper",
        description="Helpers and policy checks for Python dependency lock/spec files.",
    )
    sub = parser.add_subparsers(dest="command", required=True)

    check = sub.add_parser("check", help="Check dependency specification files")
    check.add_argument(
        "--project-root",
        default=".",
        help="Project root to inspect for dependency files",
    )
    check.add_argument(
        "--requirements",
        help="Specific requirements file to analyze",
    )
    check.add_argument(
        "--require-hashes",
        action="store_true",
        help="Require --hash entries for each pinned requirement line",
    )
    check.set_defaults(func=cmd_check)

    guide = sub.add_parser("guide", help="Print recommended generation commands")
    guide.add_argument(
        "--tool",
        choices=["pip-tools", "poetry", "plain"],
        required=True,
        help="Dependency workflow to describe",
    )
    guide.set_defaults(func=cmd_guide)

    return parser


def main(argv: Iterable[str] | None = None) -> int:
    parser = build_parser()
    args = parser.parse_args(list(argv) if argv is not None else None)
    return args.func(args)


if __name__ == "__main__":
    raise SystemExit(main())